public static client void main(Args _args)
{
    ETGLedgerVoucherTransactionController controller = new ETGLedgerVoucherTransactionController();




    if (curExt() == 'e016')
    {

        controller.parmReportName(ssrsReportStr(ETGLedgerVoucherTransaction, PrecisionDesign2));
    }

    else if (curExt() == 'y002')
    {

        controller.parmReportName(ssrsReportStr(ETGLedgerVoucherTransaction, PrecisionDesign3));
    }
    else
    {

        controller.parmReportName(ssrsReportStr(ETGLedgerVoucherTransaction, PrecisionDesign1));
    }

    controller.parmArgs(_args);
    controller.parmShowDialog(true);
    controller.startOperation();
}
